import React from 'react';
import styled from 'styled-components';

import Nav from './3nav/nav.jsx';
import Header from './2header/header.jsx';
import Main from './4main/main.jsx' 

const SWrapper = styled.div`
grid-area: 1/1/13/13;
display: grid;
grid-template-columns:repeat(12, 8.333%);  
grid-template-rows:repeat(12, 8.333%); 
background: red ;
color: black ;
font-family: 'TopSecretWoff2' ;

`


const Wrapper = () => {
  return (
<SWrapper>
<Header/>
<Nav/>
<Main/>
</SWrapper>
  );
};

export default Wrapper;
